def verify_index_integrity(index_path: str) -> Dict[str, Any]:
    """Verify the integrity of a built LEANN index."""
    meta_path = Path(index_path) / f"{Path(index_path).stem}.meta.json"

    if not meta_path.exists():
        raise FileNotFoundError(f"Index metadata file not found at {meta_path}")

    errors = []

    try:
        with open(meta_path, 'r') as f:
            metadata = json.load(f)
    except json.JSONDecodeError as e:
        errors.append(f"Invalid JSON in metadata file: {str(e)}")
        metadata = {}

    passage_count = metadata.get('passage_count', 0)

    index_file = Path(index_path)
    if not index_file.exists():
        errors.append(f"Index file not found at {index_file}")

    if errors:
        return {
            "is_valid": False,
            "passage_count": passage_count,
            "metadata_file_exists": meta_path.exists(),
            "errors": errors
        }

    try:
        searcher = LeannSearcher(index_path)
        passage_manager = searcher.passage_manager

        actual_count = len(passage_manager)

        if actual_count != passage_count:
            errors.append(f"Passage count mismatch: expected {passage_count}, got {actual_count}")

        searcher.close()
    except Exception as e:
        errors.append(f"Failed to access index: {str(e)}")

    is_valid = len(errors) == 0

    return {
        "is_valid": is_valid,
        "passage_count": passage_count,
        "metadata_file_exists": meta_path.exists(),
        "errors": errors
    }

