def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index."""
    index_path_obj = Path(index_path)
    if not index_path_obj.exists():
        raise FileNotFoundError(f"Index file not found at {index_path}")

    try:
        searcher = LeannSearcher(index_path)
        pm = searcher.passage_manager
        passages = pm.get_all_passages()

        total_passages = len(passages)
        metadata_fields = set()
        field_value_counts = defaultdict(Counter)

        for passage in passages:
            metadata = passage.metadata
            for field_name, value in metadata.items():
                metadata_fields.add(field_name)
                field_value_counts[field_name][value] += 1

        # Convert to regular dict for JSON serialization
        field_value_counts_dict = {}
        for field, counts in field_value_counts.items():
            field_value_counts_dict[field] = dict(counts)

        return {
            "total_passages": total_passages,
            "metadata_fields": sorted(list(metadata_fields)),
            "field_value_counts": field_value_counts_dict
        }

    except FileNotFoundError:
        raise FileNotFoundError(f"Index metadata file not found at {index_path}")
    except Exception as e:
        raise

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields."""
    index_path_obj = Path(index_path)
    if not index_path_obj.exists():
        raise FileNotFoundError(f"Index file not found at {index_path}")

    try:
        searcher = LeannSearcher(index_path)
        pm = searcher.passage_manager
        passages = pm.get_all_passages()

        total_passages = len(passages)
        if total_passages == 0:
            return {
                "coverage_percentage": 0.0,
                "field_coverage": {},
                "missing_fields": required_fields
            }

        # Count passages that have all required fields
        total_covered = 0
        field_counts = defaultdict(int)

        for passage in passages:
            metadata = passage.metadata
            has_all = True

            for field in required_fields:
                if field not in metadata:
                    has_all = False
                    break

            if has_all:
                total_covered += 1

            # Count how many passages have each required field
            for field in required_fields:
                if field in metadata:
                    field_counts[field] += 1

        # Determine missing fields - those not present in any passage
        missing_fields = [field for field in required_fields if field not in field_counts]

        # Calculate percentages
        coverage_percentage = (total_covered / total_passages) * 100
        field_coverage = {}
        for field, count in field_counts.items():
            field_coverage[field] = (count / total_passages) * 100

        return {
            "coverage_percentage": round(coverage_percentage, 2),
            "field_coverage": field_coverage,
            "missing_fields": missing_fields
        }

    except FileNotFoundError:
        raise FileNotFoundError(f"Index metadata file not found at {index_path}")
    except Exception as e:
        raise

