def search_with_result_expansion(
    index_path: str,
    query: str,
    expand_by_field: str,
    expansion_count: int = 1,
    top_k: int = 10
) -> List[SearchResult]:
    """Search in an index and expand results by including additional results with matching field values."""
    if expansion_count < 0:
        raise ValueError("expansion_count must be non-negative")

    try:
        searcher = LeannSearcher(index_path)
    except FileNotFoundError:
        raise FileNotFoundError(f"Index file not found: {index_path}")

    initial_results = searcher.search(query, top_k=top_k)

    expanded_results = []
    initial_ids = {result.id for result in initial_results}
    expanded_ids = set()

    for result in initial_results:
        field_value = result.metadata.get(expand_by_field)
        if field_value is None:
            continue

        expanded_query = f"{expand_by_field}:{field_value}"
        try:
            expanded_search = searcher.search(expanded_query, top_k=expansion_count)
            for exp_result in expanded_search:
                if exp_result.id not in initial_ids and exp_result.id not in expanded_ids:
                    expanded_results.append(exp_result)
                    expanded_ids.add(exp_result.id)
        except Exception:
            # Continue with other results if expansion search fails
            continue

    return initial_results + expanded_results

